87: absl::StatusOr<HeaderParserPtr>
88: HeaderParser::configure(const Protobuf::RepeatedPtrField<HeaderValueOption>& headers_to_add) {
89:   HeaderParserPtr header_parser(new HeaderParser());
90:   header_parser->headers_to_add_.reserve(headers_to_add.size());
91:   for (const auto& header_value_option : headers_to_add) {
92:     auto entry_or_error = HeadersToAddEntry::create(header_value_option);
93:     RETURN_IF_NOT_OK_REF(entry_or_error.status());
94:     header_parser->headers_to_add_.emplace_back(
95:         Http::LowerCaseString(header_value_option.header().key()),
96:         std::move(entry_or_error.value()));
97:   }
98: 
99:   return header_parser;
100: }
